struct DSU
    parent : Array(UInt64)
    parity : Array(UInt64)
    n : UInt64

    fn new(n: UInt64) : DSU
        parent = Array(n) { i.to_u64 }
        parity = Array(n) { 0.to_u64 }
        self.n = n
    end

    fn find(&self, i: UInt64) : Tuple(root: UInt64, path_parity: UInt64)
        if self.parent[i.to_int] == i {
            return Tuple(root: i, path_parity: 0.to_u64)
        }

        // Recurse to find the root and the parity from the old parent to the root
        let (root, parent_to_root_parity) = self.find(self.parent[i.to_int])

        // Update parity for i: parity[i] = old_parity[i] XOR parent_to_root_parity
        self.parity[i.to_int] = self.parity[i.to_int] xor parent_to_root_parity

        // Path compression
        self.parent[i.to_int] = root

        return Tuple(root: root, path_parity: self.parity[i.to_int])
    end

    fn union(&self, u: UInt64, v: UInt64, w: UInt64) : Bool
        let (rootU, parityU) = self.find(u)
        let (rootV, parityV) = self.find(v)

        if rootU == rootV
            // Cycle detected. Check parity.
            // Existing path parity u <-> v is parityU XOR parityV.
            // New cycle parity = (Existing path parity) XOR w
            let cycleParity = parityU xor parityV xor w

            // Edge is added only if cycleParity is even (0).
            return cycleParity == 0.to_u64
        else
            // No cycle. Merge rootV into rootU.
            self.parent[rootV.to_int] = rootU

            // Calculate the new parity for rootV relative to rootU.
            // Path: rootV --(parityV)--> v --(w)--> u --(parityU)--> rootU
            // New_parity[rootV] = parityV XOR w XOR parityU
            self.parity[rootV.to_int] = parityV xor w xor parityU

            return true
        end
    end
end

fn solve(n : Int64, edges : Array(Array(Int64))) : Int64
    let n_u64 = n.to_u64
    let dsu = DSU.new(n_u64)
    var edge_count: Int64 = 0

    for edge in edges
        let u = edge[0].to_u64
        let v = edge[1].to_u64
        let w = edge[2].to_u64

        if dsu.union(u, v, w)
            edge_count += 1
        end
    end

    return edge_count.to_int
end
