 * Solves the problem using Disjoint Set Union (DSU) with parity tracking.
 * 
 * The condition "every cycle's edge weight sum is even" is equivalent to 
 * saying that for any two nodes u and v, the path weight between them 
 * in the current graph must have a well-defined parity.
 * 
 * If we maintain for each node x, the parity of the path weight from x to the representative of its set (parent[x]),
 * then adding an edge (u, v) with weight w is valid if and only if 
 * the path parity between u and v is w (i.e., parity(u->root) XOR parity(v->root) = w).
 * 
 * Let dist[i] be the parity of the path from node i to its current parent.
 * When we process edge (u, v, w):
 * 1. Find roots: root_u, root_v.
 * 2. If root_u == root_v:
 *    - A cycle is formed. The path weight from u to v in the existing graph is 
 *      (dist[u] XOR dist[v]).
 *    - The new cycle weight is (existing_path_parity XOR w) = (dist[u] XOR dist[v] XOR w).
 *    - The edge is added only if this cycle weight is even (0).
 *    - Condition: dist[u] XOR dist[v] XOR w == 0, which means dist[u] XOR dist[v] == w.
 * 3. If root_u != root_v:
 *    - We merge the sets (e.g., merge root_v into root_u).
 *    - The new distance for root_v (relative to root_u) must be calculated:
 *      New_dist[root_v] = dist[u] XOR w XOR dist[v].
 *    - The edge is always added as it doesn't form a cycle in the current component structure.
 */
function solve(n, edges) {
    // DSU structure setup
    const parent = Array(n).fill(0).map((_, i) => i);
    // parity[i] stores the parity of the path weight from node i to its current parent.
    // 0 means even path, 1 means odd path.
    const parity = Array(n).fill(0);

    /**
     * Finds the representative (root) of the set containing i, 
     * and performs path compression while updating the parity.
     * @param {number} i The node index.
     * @returns {number} The root of the set containing i.
     */
    const find = (i) => {
        if (parent[i] === i) {
            return i;
        }
        // Recursively find the root and get the parity to the root of the parent.
        const root = find(parent[i]);

        // Update the parity for i:
        // The new parity from i to root is (old_parity[i] XOR parity_from_old_parent_to_root).
        parity[i] = parity[i] ^ parity[parent[i]];

        // Path compression
        parent[i] = root;
        return root;
    };

    let edgeCount = 0;

    for (const [u, v, w] of edges) {
        const rootU = find(u);
        const rootV = find(v);

        if (rootU === rootV) {
            // A cycle is formed. Check the cycle parity.
            // Existing path parity between u and v is parity[u] ^ parity[v].
            // New cycle parity = (Existing path parity) XOR w
            const cycleParity = parity[u] ^ parity[v] ^ w;

            // Edge is added only if the cycle parity is even (0).
            if (cycleParity === 0) {
                edgeCount++;
            }
        } else {
            // No cycle formed within the current components. Merge sets.
            // Merge rootV into rootU (arbitrarily).
            parent[rootV] = rootU;

            // Calculate the new parity for rootV relative to rootU.
            // We want: parity[rootV] (new) = parity from rootV to rootU.
            // Path: rootV --(parity[v])--> v --(w)--> u --(parity[u])--> rootU
            // Parity from rootV to rootU = parity[v] XOR w XOR parity[u].
            parity[rootV] = parity[v] ^ w ^ parity[u];

            edgeCount++;
        }
    }

    return edgeCount;
}

